/**
 * `mode=link` attaches the identity to the signed-in account instead of signing in. Sets a signed, single-use state cookie; the callback is refused without it.
 * @summary Redirect to the provider (a browser navigation, not a fetch)
 */
export const getStartOAuthUrl = (
  provider: OAuthProvider,
  params?: StartOAuthParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/auth/oauth/${provider}?${stringifiedParams}`
    : `/api/auth/oauth/${provider}`;
};

export const startOAuth = async (
  provider: OAuthProvider,
  params?: StartOAuthParams,
  options?: RequestInit,
): Promise<unknown> => {
  return customFetch<unknown>(getStartOAuthUrl(provider, params), {
    ...options,
    method: "GET",
  });
};

